/**
 * Barrier Map Page — Shows confirmed barrier insights.
 *
 * Displays barrier cards colored by severity:
 * - high → red, medium → amber, low → blue
 * - Shows barrier type, severity, description, count, solution
 * - Only shows type === 'barrier' and reviewStatus === 'confirmed'
 */

import React, { useEffect, useMemo } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  Chip,
  Grid,
  LinearProgress,
} from '@mui/material';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';
import { useBrandStore } from '@/shared/stores/brandStore';
import { useInsightStore } from '@/shared/stores/insightStore';
import type { Barrier } from '@/shared/types/insight';

/** Severity color mapping */
const SEVERITY_COLORS = {
  high: { color: 'error' as const, bg: 'error.50', border: 'error.main', label: '高' },
  medium: { color: 'warning' as const, bg: 'warning.50', border: 'warning.main', label: '中' },
  low: { color: 'info' as const, bg: 'info.50', border: 'info.main', label: '低' },
};

/** Barrier type display name */
const BARRIER_TYPE_LABELS: Record<string, string> = {
  price: '价格',
  trust: '信任',
  effect: '效果',
  audience: '人群',
  usage: '使用',
  competitor: '竞品',
  risk: '风险',
  information: '信息',
};

const BarrierMapPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const brand = useBrandStore((s) => s.getCurrentBrand());
  const insights = useInsightStore((s) => s.insights);
  const loadInsights = useInsightStore((s) => s.loadInsights);

  const brandId = currentBrandId ?? '';

  useEffect(() => {
    if (brandId) loadInsights(brandId);
  }, [brandId, loadInsights]);

  // Filter: only confirmed barriers
  const barriers = useMemo(
    () =>
      insights.filter(
        (i) => i.type === 'barrier' && i.reviewStatus === 'confirmed',
      ) as Barrier[],
    [insights],
  );

  // Sort by severity
  const severityOrder = { high: 0, medium: 1, low: 2 };
  const sorted = useMemo(
    () => [...barriers].sort((a, b) => (severityOrder[a.severity] ?? 1) - (severityOrder[b.severity] ?? 1)),
    [barriers],
  );

  // Max count for progress bar
  const maxCount = Math.max(...sorted.map((b) => b.count), 1);

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Header */}
      <Box
        sx={{
          p: 2,
          borderBottom: '1px solid',
          borderColor: 'divider',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
        }}
      >
        <Box>
          <Typography variant="h6" fontWeight={700}>
            🛡️ 障碍地图
          </Typography>
          <Typography variant="body2" color="text.secondary">
            {brand?.name ?? ''} · 已确认障碍 {sorted.length} 条
          </Typography>
        </Box>
      </Box>

      {/* Content */}
      <Box sx={{ flex: 1, overflow: 'auto', p: 2 }}>
        {sorted.length === 0 ? (
          <Box
            sx={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              height: '100%',
              gap: 2,
            }}
          >
            <WarningAmberIcon sx={{ fontSize: 48, color: 'text.disabled' }} />
            <Typography variant="body1" color="text.secondary">
              暂无已确认的障碍洞察
            </Typography>
            <Typography variant="caption" color="text.disabled">
              请先在 AI 工作台运行分析，然后在审核工作台确认洞察
            </Typography>
          </Box>
        ) : (
          <Grid container spacing={2}>
            {sorted.map((barrier) => {
              const sev = SEVERITY_COLORS[barrier.severity] ?? SEVERITY_COLORS.medium;
              const typeLabel = BARRIER_TYPE_LABELS[barrier.barrierType] ?? barrier.barrierType;

              return (
                <Grid item xs={12} sm={6} md={4} key={barrier.id}>
                  <Card
                    sx={{
                      height: '100%',
                      display: 'flex',
                      flexDirection: 'column',
                      borderLeft: `4px solid`,
                      borderColor: sev.border,
                    }}
                  >
                    <CardContent sx={{ flex: 1 }}>
                      {/* Severity + Type */}
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1 }}>
                        <Chip
                          label={`${sev.label}严重度`}
                          size="small"
                          color={sev.color}
                          sx={{ fontWeight: 600, fontSize: 11 }}
                        />
                        <Chip
                          label={typeLabel}
                          size="small"
                          variant="outlined"
                          sx={{ fontSize: 11 }}
                        />
                      </Box>

                      {/* Title */}
                      <Typography variant="subtitle2" fontWeight={600} gutterBottom>
                        {barrier.title}
                      </Typography>
                      <Typography
                        variant="body2"
                        color="text.secondary"
                        sx={{
                          mb: 1.5,
                          display: '-webkit-box',
                          WebkitLineClamp: 3,
                          WebkitBoxOrient: 'vertical',
                          overflow: 'hidden',
                        }}
                      >
                        {barrier.content}
                      </Typography>

                      {/* Count bar */}
                      <Box sx={{ mb: 1.5 }}>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 0.5 }}>
                          <Typography variant="caption" color="text.secondary">
                            提及次数
                          </Typography>
                          <Typography variant="caption" fontWeight={600}>
                            {barrier.count}
                          </Typography>
                        </Box>
                        <LinearProgress
                          variant="determinate"
                          value={(barrier.count / maxCount) * 100}
                          color={sev.color}
                          sx={{ height: 6, borderRadius: 3 }}
                        />
                      </Box>

                      {/* Solution */}
                      {barrier.solution && (
                        <Box
                          sx={{
                            mt: 1,
                            p: 1,
                            borderRadius: 1,
                            bgcolor: 'action.hover',
                          }}
                        >
                          <Typography variant="caption" fontWeight={600} color="text.secondary">
                            💡 解决方案
                          </Typography>
                          <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mt: 0.25 }}>
                            {barrier.solution}
                          </Typography>
                        </Box>
                      )}
                    </CardContent>
                  </Card>
                </Grid>
              );
            })}
          </Grid>
        )}
      </Box>
    </Box>
  );
};

export default BarrierMapPage;
